const closeBelow = {
  'pg_details-box':            675,
  'pg_details-close-tab-l':   1119,
  'pg_details-close-tab-p':   1023,
  'pg_details-close-phone-l':  767,
  'pg_details-close-phone-p':  479,
  'pg_details-closed':           0
};
const openAbove = {
  'pg_details-open-tab-l':    1119,
  'pg_details-open-tab-p':    1023,
  'pg_details-open-phone-l':   767,
  'pg_details-open-phone-p':   479
};
function toggleAccordions() {
  const w = window.innerWidth;
  Object.entries(closeBelow).forEach(([cls, bp]) => {
    document.querySelectorAll(`.${cls}`).forEach(acc => {
      w > bp ? acc.setAttribute('open', '') : acc.removeAttribute('open');
    });
  });
  Object.entries(openAbove).forEach(([cls, bp]) => {
    document.querySelectorAll(`.${cls}`).forEach(acc => {
      w > bp ? acc.removeAttribute('open') : acc.setAttribute('open', '');
    });
  });
}
toggleAccordions();
window.addEventListener('resize', toggleAccordions);

(function () {
  'use strict';
  function patchBreakdanceForms() {
    document.querySelectorAll('textarea[type]').forEach(function (el) {
      el.removeAttribute('type');
    });
    document.querySelectorAll('[aria-describedby]').forEach(function (input) {
      var targetId = input.getAttribute('aria-describedby');
      if (targetId && !document.getElementById(targetId)) {
        input.removeAttribute('aria-describedby');
      }
    });
    document.querySelectorAll('.bde-popup').forEach(function(popup) {
      var form = popup.querySelector('form[id]');
      if (!form) return;
      var namespace = form.id;
      popup.querySelectorAll('input[id], textarea[id], select[id]').forEach(function(field) {
        var oldId = field.getAttribute('id');
        var newId = namespace + '--' + oldId;
        field.setAttribute('id', newId);
        var label = popup.querySelector('label[for="' + oldId + '"]');
        if (label) label.setAttribute('for', newId);
      });
    });
    document.querySelectorAll('.breakdance-form-field--hpinput').forEach(function(wrapper) {
      var form = wrapper.closest('form');
      if (form && form.parentNode) {
        form.parentNode.insertBefore(wrapper, form.nextSibling);
      }
    });
  }
  if (document.readyState === 'loading') {
    document.addEventListener('DOMContentLoaded', patchBreakdanceForms);
  } else {
    patchBreakdanceForms();
  }
})();
